var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 뒤","JPN":"一週間後","ENG":"One week later","TWN":"一週以後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이게 차원함선이라는 건가……? 엄청나잖아……?","JPN":"これが次元艦船ってやつか……？　すごいな……","ENG":"This is a dimensional ship...? It's huge...!","TWN":"這就是次元艦船嗎……？太大了吧……？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"뭘 그렇게 하나하나 놀라고 있습니까요?","JPN":"いちいち驚きすぎでやんす。","ENG":"What are you so surprised about?","TWN":"這有什麼好驚訝的？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국 본부에는 이런 함선들이 적어도 수십 대는 더 있습니다요.","JPN":"管理局の本部にはこういう艦船が数十隻はあるでやんす。","ENG":"There are at least dozens of ships like this at the Administration HQ.","TWN":"管理局總部至少有數十艘這樣的艦船。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"수십 대라고……?","JPN":"数十隻も……？","ENG":"Dozens...?","TWN":"數十艘……？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 에잉…… 쯧쯧!","JPN":"それと……ちっちっち！","ENG":"And– Ugh, tsk tsk.","TWN":"還有……嘖嘖！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"함선 탈때는 신발 벗고 타야 하는 것도 모릅니까요?","JPN":"艦船に乗る時は靴を脱ぐのが常識でやんすよ！","ENG":"Don't you know you have to take off your shoes when you get on the ship?","TWN":"你不知道艦船內必須脫鞋嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L15_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아주 매너 점수가 빵점입니다요!","JPN":"まったくマナーがなってない人でやんす！","ENG":"You're so uncivilized!","TWN":"你真是一點禮貌都沒有！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그, 그런 거였어!?","JPN":"そ、そうだったのか！？","ENG":"R-really?!","TWN":"是、是嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐야! 다들 신고 있잖아, 죽을래?","JPN":"何だよ、みんな靴履いてるじゃないか！　嘘ついたな！","ENG":"Hey! Everyone else is wearing their shoes! You...!","TWN":"什麼啊！大家都穿著的啊，你想死嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"킥킥, 속았습니다요~ 바보입니다요~ 아주 시골 고양이입니다요~","JPN":"ききき、騙されたでやんす～　バカでやんす～　田舎くさい猫でやんす～","ENG":"Keke! Fooled you! You're so gullible! Looks like you're a hillbilly cat!","TWN":"嘻嘻，上當了吧～笨蛋～沒見識的小貓咪～"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"우갹!!","JPN":"うぎゃあ！！","ENG":"Eep!!","TWN":"呃啊！！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그나저나 우리 전대원들 말고 관리국 지원병력도 많이 있잖아?","JPN":"それにしても、うちの戦隊員の他にも管理局の支援兵力がけっこうついて来るんだな。","ENG":"By the way, I see a lot of support troops from the Administration besides our division here.","TWN":"話說回來，除了我們戰隊員之外，管理局還有很多的支援部隊吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"우으…… 그야 당연한 거 아닙니까요.","JPN":"うう……そんなの当たり前でやんす。","ENG":"Ooh... Of course, you do.","TWN":"呃……那當然。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아무리 소규모 작전이라고 해도 이면세계에서는 어떤 일이 벌어질지 모르는 겁니다요.","JPN":"いくら小規模の作戦とはいえ、裏世界では何が起きるかわからないでやんすから。","ENG":"Even if it's a small-scale operation, nobody knows what will happen in the Counterside.","TWN":"誰也不知道在異界裡會發生什麼，無論是多麼微小的作戰。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"카운터와 지원병력이 합을 맞추는 건 기본입니다요.","JPN":"カウンターと支援兵力が力を合わせるのは当然でやんす。","ENG":"Everyone knows Counters and troops have to work together.","TWN":"制裁者和支援部隊相互配合才是最基本的。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"게다가 전대장님도 안 계신 상황이니…….","JPN":"それに、戦隊長も不在だから……","ENG":"And because Commander isn't here...","TWN":"而且，戰隊長也不在……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러고 보니, 그…… 라이오넬 전대장이라고 했나? 그 사람은 어디 있는 거야?","JPN":"そういえば、その……ライオネル戦隊長だっけ？　その人はどこにいるんだ？","ENG":"Oh, now that you mention it... Commander Lionel, was it? Where is he, anyway?","TWN":"現在我想起來了，你是說……萊諾戰隊長嗎？他人到底在哪裡？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"부재중이라는 이야기를 듣긴 했는데 여태 한 번을 못 봤네?","JPN":"しばらく留守にしてるとは聞いたけど、なかなか帰って来ないんだな。","ENG":"I heard he's away, but I've never seen him once.","TWN":"聽說他不在隊裡，我到現在還一次沒見過他呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"헤엥? 아직 그런 것도 모르고 있었습니까요?","JPN":"ええ？　まだ知らないでやんすか？","ENG":"Huh? You still don't know?","TWN":"欸？你還不知道嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그야 아무도 가르쳐 준 적이 없으니까. 꼭 알아야 하는 거야?","JPN":"そりゃあ、誰も教えてくれなかったからな。知る必要ってあるのか？","ENG":"Yeah, because no one ever told me. Do I have to know?","TWN":"從前又沒有人告訴過我……難道我一定要知道這些嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히이…….","JPN":"キヒイ……","ENG":"Hngh...","TWN":"吱……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 작전 시작에 앞서 마지막으로 브리핑하겠습니다.","JPN":"では、作戦を開始する前に、最後のブリーフィングを行います。","ENG":"Then, let's do one last briefing before starting the operation.","TWN":"現在，開始作戰之前的最後一次簡報。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이번 수색 작전의 목표는 행방불명 라이오넬 전대장님과 전대원들의 수색 재개입니다.","JPN":"今回の捜索作戦の目標は、行方不明になったライオネル戦隊長と他戦隊員たちの捜索再開です。","ENG":"The objective of this operation is to resume the search for Commander Lionel and our MIA members.","TWN":"本次偵察作戰，將重啟對失蹤的萊諾戰隊長和其它戰隊員的搜尋工作。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"행방불명……? 수색 재개라고……?","JPN":"行方不明……？　捜索再開だと……？","ENG":"MIA...? Resume searching...?","TWN":"失蹤……？搜尋工作……？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"따라서 이번 다이브의 목적지는 전대장님의 부대가 마지막으로 신호를 보냈던 좌표입니다.","JPN":"よって、今回のダイブの目的地は戦隊長の部隊が最後に信号を送信した座標となります。","ENG":"Therefore, our dive destination will be the last coordinates Commander's squad sent us.","TWN":"因此，本次躍入的目的地為，戰隊長最後一次發出訊號的座標。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"목표 좌표에 도착하면 해당 이면세계에서 1차 수색을 진행.","JPN":"目標座標に着いたら、該当の裏世界で1次捜索を進行。","ENG":"Once we arrive at the coordinates, we will conduct the first search in the Counterside.","TWN":"抵達目標位置後，我們將在該異界中進行第一次偵察。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 후, 조금씩 심도를 낮춰가며 전대장님의 부대가 목표로 했던 항로를 추적합니다.","JPN":"その後、少しずつ深度を深め、戦隊長の部隊が目指していた航路を追跡します。","ENG":"Afterward, we will dive deeper into where the Commander's squad was headed.","TWN":"之後，逐漸增加深度，追蹤戰隊長部隊的行跡路線。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"다만 사전에 말씀드렸다시피, 이번 작전은 신입 대원의 신고식을 겸하고 있습니다.","JPN":"ただし、事前にお伝えした通り、今回の作戦は新入隊員の通過儀礼を兼ねています。","ENG":"However, as you may know, we will also be doing our rookie's debut in this operation.","TWN":"不過，正如我之前提到的，這次作戰也是新人的出道。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"심도와 관계없이 그림자가 출몰하면 격파 후, 즉시 현실로 부상하겠습니다.","JPN":"深度と関係なくシャドウが出現した場合、撃破してすぐに現実へ浮上します。","ENG":"Regardless of depth, we will resurface to the Normalside after eliminating the Shadow, if it appears.","TWN":"無論何種深度，只要有暗影出現，我們將會在擊敗該暗影後立即躍出至現世。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장님의 부대에 대한 수색은 추후 작전에서 다시 수행합니다.","JPN":"そして戦隊長部隊の捜索は次回の作戦より行います。","ENG":"We will resume the search for Commander's squad in a later operation.","TWN":"至於戰隊長小隊的搜查工作，會在之後的作戰中再次進行。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"하하, 신고식이라니 그때가 그립네!","JPN":"はは、通過儀礼か！　懐かしいな！","ENG":"Haha, a debut? I miss those days!","TWN":"哈哈，出道，真懷念那個時候啊！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"앨리스! 그림자가 나타나도 너무 벌벌 떨지 말라고!","JPN":"アリス！　シャドウが出てきてもビビるなよ！","ENG":"Alice! Don't tremble too much if a Shadow appears!","TWN":"艾莉絲！暗影出現時不要太緊張！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"너무 무서우면 부전대장님께 부탁하라구! 하하핫!","JPN":"怖かったら副戦隊長に頼るんだな！　はははっ！","ENG":"If you're too scared, you can always ask your Deputy Commander to help you! Hahaha!","TWN":"如果你太害怕，就去拜託副戰隊長吧！哈哈哈！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"시끄러워! 너희들도 다 처음이 있었을 거 아니야!","JPN":"うるさい！　おまえらにだって初めてがあったんだろう！","ENG":"Shut up! You all had your first time too!","TWN":"閉嘴！誰都有第一次吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제길, 두고 보자고! 보란듯이 그림자를 박살내 줄 테니까!","JPN":"くそ、見てろよ！　シャドウなんかぶちのめしてやる！","ENG":"Ugh, just you wait! I'll go crush that Shadow just to prove you wrong!","TWN":"該死，走著瞧吧！我會消滅暗影給你看的！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"키히히, 혹시 긴장한 거 아닙니까요?","JPN":"キヒヒ、もしかして緊張してるでやんすか？","ENG":"Kehehe! Are you nervous?","TWN":"嘻嘻嘻，你不緊張嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"너무 긴장하면 다이브 멀미합니다요~","JPN":"緊張しすぎるとダイブ酔いするでやんす～","ENG":"You're gonna get dive sickness if you're too nervous.","TWN":"太緊張的話，躍入時可是會暈的喔～"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아얏!!","JPN":"イタッ！！","ENG":"Ouch!","TWN":"啊呀！！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"너도 시끄러워, 완두콩. 긴장 같은 거 하나도 안 했다고!","JPN":"うるさい、ちんちくりん。緊張なんかまったくしてねえよ！","ENG":"You too, green pea! Shut it! I'm not nervous at all!","TWN":"你好吵，豌豆。我一點也不緊張！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"우씨! 나름 걱정해 준 겁니다요!","JPN":"きい！！　あたいは心配してやったんでやんす！","ENG":"Errgh! I was just being considerate!","TWN":"欸！我是真的擔心你欸！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이면세계 목표지점의 위상좌표 계산 중……. 계산 완료!","JPN":"裏世界の目標地点の位相座標を計算中……計算完了！","ENG":"Calculating phase coordinates for the Counterside destination... Calculations complete!","TWN":"正在計算異界目標地點的位置座標……計算完成！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L17_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이터니움 드라이브 에너지 충전 중……. 임계치 돌파!","JPN":"エタニウムドライブのエネルギーチャージ中……臨界値突破！","ENG":"Charging Eternium Drive... Critical point reached!","TWN":"永恆之金驅動器能量開始充能……即將達到臨界值！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"야크샤 부전대장님, 다이브 준비 완료되었습니다.","JPN":"ヤクシャー副戦隊長、ダイブ準備完了しました。","ENG":"Yaksha Deputy Commander, we're ready to dive.","TWN":"夜叉副戰隊長，已完成躍入準備工作。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……좋아.","JPN":"……よし。","ENG":"...All right.","TWN":"……很好。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"야크샤 전대, 다이브 개시!","JPN":"ヤクシャー戦隊、ダイブ開始！","ENG":"The Yaksha Division, commence dive!","TWN":"夜叉戰隊，開始躍入！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이터니움 드라이브, 출력 전개!","JPN":"エタニウムドライブ、出力全開！","ENG":"The Eternium Drive is at full power!","TWN":"永恆之金驅動器，動力全開！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"다이브 개시합니다!","JPN":"ダイブ、開始します！","ENG":"Commencing dive!","TWN":"開始躍入！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"함 내의 야크샤 전대에 전달 드립니다.","JPN":"艦内のヤクシャー戦隊にお伝えします。","ENG":"To all the Yaksha Division on board.","TWN":"正在傳送給艦船內的夜叉戰隊。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"본 함, 목표 좌표에 무사히 도착했습니다.","JPN":"本艦は無事目標座標に到着しました。","ENG":"We have safely reached our destination.","TWN":"本艦已安全抵達目標座標。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐야, 진짜 순식간이잖아……?","JPN":"本当に……一瞬だったな……","ENG":"Huh? We're here already...?","TWN":"什麼啊，一瞬間就……？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"여기가 이면세계라고……?","JPN":"ここが裏世界なのか……？","ENG":"This is the Counterside...?","TWN":"這是異界……？"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아무것도 없어. 마치 우주를 표류하고 있는 것 같은 느낌이야.","JPN":"何もない。まるで宇宙を漂流しているような感じだ。","ENG":"But there's nothing here. I feel like I'm just drifting away in space.","TWN":"好荒蕪的樣子。感覺就像在太空中漂流。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음, 그렇네.","JPN":"うん、そうね。","ENG":"Mm... You're right.","TWN":"唔，你說的沒錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"마지막으로 전대장님을 찾으러 왔을 때보다 훨씬 황폐해졌어.","JPN":"最後に戦隊長を探しに来た時に比べて、更に荒廃してる。","ENG":"It's a lot more barren than the last time we went to search for Commander.","TWN":"比我上次來尋找戰隊長時還要荒蕪。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그땐 이정도까지는 아니었는데 말이야.","JPN":"あの時は、こんなに酷くなかったけど。","ENG":"It wasn't this devastated that time.","TWN":"當時還沒有到這個程度。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이미 멸망해 버린 세계라고 해도, 여전히 시간은 흐르나 봐.","JPN":"既に滅んだ世界でも、いまだ時間は流れ続けるのね。","ENG":"Even if this world is already in ruins, I guess time still seems to pass.","TWN":"看來即使世界已經毀滅，時間依然在不停流逝。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐 하나만 물어봐도 돼?","JPN":"一つ、聞いてもいいか？","ENG":"Can I ask you something?","TWN":"我可以問你一件事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐가 궁금해? 우리 길고양이가 물어보시는데, 대답해드려야지.","JPN":"何？　野良猫の質問ならなんでも答えてあげないとね。","ENG":"What do you want to know? Our stray cat is asking, so I must answer.","TWN":"當然，你想知道什麼？我們的流浪貓發問了，我怎麼能不回答？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"여기가…… 라이오넬 전대장이 행방불명된 곳이라고 했지?","JPN":"ここが……ライオネル戦隊長が行方不明になった場所なんだろ？","ENG":"You said that... this is where Commander Lionel went missing, right?","TWN":"這裡……你說這裡是萊諾戰隊長失蹤的地方吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럼, 너희는 그동안 줄곧 사라진 전대장을 찾고 있었던 거야?","JPN":"じゃあおまえらは、今まで……消えた戦隊長を探し続けていたのか？","ENG":"And you've been looking for him all this time?","TWN":"那麼，你們一直在尋找失蹤的戰隊長嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……물론이야.","JPN":"……その通りよ。","ENG":"...Of course.","TWN":"……當然。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리에게는 가족 같은 사람이었거든.","JPN":"私たちにとっては、家族みたいな人だったからね。","ENG":"He's like our family.","TWN":"他對我們來說就像家人一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"가족이라고……?","JPN":"家族……？","ENG":"Family...?","TWN":"家人嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"부전대장님!","JPN":"副戦隊長！","ENG":"Deputy Commander!","TWN":"副戰隊長！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"본 함의 출현을 감지한 침식체들이 주변에 집결하고 있습니다!","JPN":"本艦の出現を感知した侵食体が集まってきています！","ENG":"C.O.s have detected our ship, and are now assembling in our vicinity!","TWN":"侵蝕體已經感知到了本艦的出現，正在向艦體周圍聚集！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"함 내의 모든 전투원은 출격 준비!","JPN":"艦内の全戦闘員、出撃準備を！","ENG":"All combatants on board, get ready to deploy!","TWN":"艦船內的全體戰鬥人員做好出擊準備！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"일대의 침식체들을 격파하여 강하 지점을 확보한다!","JPN":"一帯の侵食体を撃破し、降下地点を確保する！","ENG":"Eliminate the C.O.s in the area and secure the drop point!","TWN":"清除該區域的侵蝕體，確保著陸點！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 이거 어쩌지?","JPN":"ふふ、参ったね。","ENG":"Fu fuu. Oh, dear.","TWN":"呵呵，這可怎麼辦呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리 사소한 추억담은 나중에 나누는 게 어떨까?","JPN":"思い出話をするのはもうちょっと後にしない？","ENG":"Perhaps we'll share more of my memories later?","TWN":"這些回憶，之後再來給你分享吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……알겠어.","JPN":"……わかった。","ENG":"...Okay.","TWN":"……知道了。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"일단, 작전에 집중할게.","JPN":"今は作戦に集中しよう。","ENG":"I'll focus on the task at hand.","TWN":"那麼先專心作戰。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};